`.`content`,'9'),'') as decimal(3,1)) end)) when isnull(max((case when (`q`.`export_content` = 'visionL') then cast(nullif(nullif(`a`.`content`,'9'),'') as decimal(3,1)) end))) then max((case when (`q`.`export_content` = 'visionR') then cast(nullif(nullif(`a`.`content`,'9'),'') as decimal(3,1)) end)) else least(max((case when (`q`.`export_content` = 'visionR') then cast(nullif(nullif(`a`.`content`,'9'),'') as decimal(3,1)) end)),max((case when (`q`.`export_content` = 'visionL') then cast(nullif(nullif(`a`.`content`,'9'),'') as decimal(3,1)) end))) end) AS `naked_min` from (((`healthdetection_2025`.`bus_doctor_answer` `a` join `healthdetection_2025`.`bus_question` `q` on(((`q`.`question_id` = `a`.`question_id`) and (`q`.`del_flag` = '0')))) left join `healthdetection_2025`.`bus_option` `o` on(((`o`.`option_id` = `a`.`option_id`) and (`o`.`del_flag` = '0')))) join `healthdetection_2025`.`bus_student` `s` on(((`s`.`student_id` = `a`.`student_id`) and (`s`.`del_flag` = '0')))) where ((`a`.`del_flag` = '0') and (`a`.`table_id` in (3,4,5))) group by `a`.`project_id`,`a`.`year`,`a`.`student_id`) `t`;
CREATE DEFINER=`root`@`%` PROCEDURE `scan_string_date_columns`()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE v_table  VARCHAR(64);
    DECLARE v_column VARCHAR(64);

    DECLARE cur CURSOR FOR
        SELECT TABLE_NAME, COLUMN_NAME
        FROM information_schema.COLUMNS
        WHERE TABLE_SCHEMA = 'healthdetection_2025'
          AND DATA_TYPE IN ('char','varchar','text','tinytext','mediumtext','longtext');

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    -- 每次扫描前清空结果
    TRUNCATE TABLE suspect_date_columns;

    OPEN cur;

    read_loop: LOOP
        FETCH cur INTO v_table, v_column;
        IF done THEN
            LEAVE read_loop;
        END IF;

        SET @sql = CONCAT(
            'INSERT INTO suspect_date_columns ',
            '  (table_name, column_name, total_rows, date_like_rows, sample_limit, check_formats) ',
            'SELECT ',
            '  ''', v_table, ''' AS table_name, ',
            '  ''', v_column, ''' AS column_name, ',
            '  COUNT(*) AS total_rows, ',
            '  SUM(CASE ',
            '        WHEN STR_TO_DATE(`', v_column, '` , ''%Y-%m-%d'') IS NOT NULL ',
            '          OR STR_TO_DATE(`', v_column, '` , ''%Y-%m-%d %H:%i:%s'') IS NOT NULL ',
            '          OR STR_TO_DATE(`', v_column, '` , ''%Y/%m/%d'') IS NOT NULL ',
            '          OR STR_TO_DATE(`', v_column, '` , ''%Y%m%d'') IS NOT NULL ',
            '        THEN 1 ELSE 0 ',
            '      END) AS date_like_rows, ',
            '  1000 AS sample_limit, ',
            '  ''%Y-%m-%d,%Y-%m-%d %H:%i:%s,%Y/%m/%d,%Y%m%d'' AS check_formats ',
            'FROM `healthdetection_2025`.`', v_table, '` ',
            'WHERE `', v_column, '` IS NOT NULL ',
            '  AND `', v_column, '` <> '''' ',
            'LIMIT 1000'
        );

        PREPARE stmt FROM @sql;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;
    END LOOP;

    CLOSE cur;
END;
CREATE DEFINER=`root`@`%` PROCEDURE `scan_string_date_columns_safe`()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE v_table  VARCHAR(128);
    DECLARE v_column VARCHAR(128);

    -- 所有字符串列
    DECLARE cur CURSOR FOR
        SELECT TABLE_NAME, COLUMN_NAME
        FROM information_schema.COLUMNS
        WHERE TABLE_SCHEMA = 'healthdetection_2025'
          AND DATA_TYPE IN ('char','varchar','text','tinytext','mediumtext','longtext');

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    TRUNCATE TABLE suspect_date_columns;

    OPEN cur;
    read_loop: LOOP
        FETCH cur INTO v_table, v_column;
        IF done THEN
            LEAVE read_loop;
        END IF;

        SET @sql = CONCAT(
            'INSERT INTO suspect_date_columns ',
            '  (table_name, column_name, total_rows, date_like_rows, ratio, sample_limit, checked_formats) ',
            'SELECT ',
            '  ''', v_table, ''', ',
            '  ''', v_column, ''', ',
            '  COUNT(*) AS total_rows, ',

            -- ================== date_like_rows：加 IFNULL，避免 NULL ==================
            '  IFNULL(SUM( CASE ',
            '        WHEN (',
            -- 1) YYYY-MM-DD
            '              `', v_column, '` REGEXP ''^[0-9]{4}-[0-9]{2}-[0-9]{2}$'' ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,1,4) AS UNSIGNED) BETWEEN 1900 AND 2100 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,6,2) AS UNSIGNED) BETWEEN 1 AND 12 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,9,2) AS UNSIGNED) BETWEEN 1 AND 31 ',
            '        ) ',
            '        OR (',
            -- 2) YYYY-MM-DD HH:MM:SS
            '              `', v_column, '` REGEXP ''^[0-9]{4}-[0-9]{2}-[0-9]{2} [0-9]{2}:[0-9]{2}:[0-9]{2}$'' ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,1,4) AS UNSIGNED) BETWEEN 1900 AND 2100 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,6,2) AS UNSIGNED) BETWEEN 1 AND 12 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,9,2) AS UNSIGNED) BETWEEN 1 AND 31 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,12,2) AS UNSIGNED) BETWEEN 0 AND 23 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,15,2) AS UNSIGNED) BETWEEN 0 AND 59 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,18,2) AS UNSIGNED) BETWEEN 0 AND 59 ',
            '        ) ',
            '        OR (',
            -- 3) YYYY/MM/DD
            '              `', v_column, '` REGEXP ''^[0-9]{4}/[0-9]{2}/[0-9]{2}$'' ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,1,4) AS UNSIGNED) BETWEEN 1900 AND 2100 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,6,2) AS UNSIGNED) BETWEEN 1 AND 12 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,9,2) AS UNSIGNED) BETWEEN 1 AND 31 ',
            '        ) ',
            '        OR (',
            -- 4) YYYYMMDD
            '              `', v_column, '` REGEXP ''^[0-9]{8}$'' ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,1,4) AS UNSIGNED) BETWEEN 1900 AND 2100 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,5,2) AS UNSIGNED) BETWEEN 1 AND 12 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,7,2) AS UNSIGNED) BETWEEN 1 AND 31 ',
            '        ) ',
            '      THEN 1 ELSE 0 ',
            '      END ),0) AS date_like_rows, ',
            -- ================== date_like_rows 结束 ==================

            -- ================== ratio：同样加 IFNULL，空表时给 0 ==================
            '  ROUND( ',
            '    IFNULL( ',
            '      SUM( CASE ',
            '        WHEN (',
            '              `', v_column, '` REGEXP ''^[0-9]{4}-[0-9]{2}-[0-9]{2}$'' ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,1,4) AS UNSIGNED) BETWEEN 1900 AND 2100 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,6,2) AS UNSIGNED) BETWEEN 1 AND 12 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,9,2) AS UNSIGNED) BETWEEN 1 AND 31 ',
            '        ) ',
            '        OR (',
            '              `', v_column, '` REGEXP ''^[0-9]{4}-[0-9]{2}-[0-9]{2} [0-9]{2}:[0-9]{2}:[0-9]{2}$'' ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,1,4) AS UNSIGNED) BETWEEN 1900 AND 2100 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,6,2) AS UNSIGNED) BETWEEN 1 AND 12 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,9,2) AS UNSIGNED) BETWEEN 1 AND 31 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,12,2) AS UNSIGNED) BETWEEN 0 AND 23 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,15,2) AS UNSIGNED) BETWEEN 0 AND 59 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,18,2) AS UNSIGNED) BETWEEN 0 AND 59 ',
            '        ) ',
            '        OR (',
            '              `', v_column, '` REGEXP ''^[0-9]{4}/[0-9]{2}/[0-9]{2}$'' ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,1,4) AS UNSIGNED) BETWEEN 1900 AND 2100 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,6,2) AS UNSIGNED) BETWEEN 1 AND 12 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,9,2) AS UNSIGNED) BETWEEN 1 AND 31 ',
            '        ) ',
            '        OR (',
            '              `', v_column, '` REGEXP ''^[0-9]{8}$'' ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,1,4) AS UNSIGNED) BETWEEN 1900 AND 2100 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,5,2) AS UNSIGNED) BETWEEN 1 AND 12 ',
            '          AND  CAST(SUBSTRING(`', v_column, '`,7,2) AS UNSIGNED) BETWEEN 1 AND 31 ',
            '        ) ',
            '      THEN 1 ELSE 0 ',
            '      END ) / NULLIF(COUNT(*),0), ',
            '      0 ',
            '    ), ',
            '    4 ',
            '  ) AS ratio, ',
            -- ================== ratio 结束 ==================

            '  1000 AS sample_limit, ',
            '  ''pattern: YYYY-MM-DD,YYYY-MM-DD HH:MM:SS,YYYY/MM/DD,YYYYMMDD (纯规则判断)'' AS checked_formats ',
            'FROM `healthdetection_2025`.`', v_table, '` ',
            'WHERE `', v_column, '` IS NOT NULL ',
            '  AND `', v_column, '` <> '''' ',
            'LIMIT 1000'
        );

        PREPARE stmt FROM @sql;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;
    END LOOP;

    CLOSE cur;
END;
BEGIN;
LOCK TABLES `healthdetection_2025`.`bus_logic_relation` WRITE;
DELETE FROM `healthdetection_2025`.`bus_logic_relation`;
